def square(x: float) -> float:
    return x * x

def cube(x: float) -> float:
    return x * x * x

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

PI: float = 3.14159
E: float = 2.71828

