def reverse_string(s: str) -> str:
    result: str = ""
    i: int = len(s) - 1
    while i >= 0:
        result = result + str(s[i])
        i = i - 1
    return result

def capitalize_words(s: str) -> str:
    if len(s) == 0:
        return s
    first: str = str(s[0]).upper()
    rest: str = s[1:len(s)].lower()
    return first + rest

